		public LoreBook( Serial serial ) : base( serial )
		{
		}

		public override void Serialize( GenericWriter writer )
		{
			base.Serialize( writer );
			writer.WriteEncodedInt( (int)0 );
		}

		public override void Deserialize( GenericReader reader )
		{
			base.Deserialize( reader );
			int version = reader.ReadEncodedInt();

			if ( BookTitle == "Staff of Five" )
			{
				BookTitle = "Staff of Five Parts";
				Name = "Staff of Five Parts";
			}

			GetText( this );
		}

		public static void GetText( LoreBook book )
		{
			if ( book.BookTitle == "Akalabeth's Tale" ){ book.BookText = "Mondain, segundo filho de Wolfgang, um grande rei dos tempos antigos, desejou obter a herança de seu irmão e, por isso, usou seus grandes poderes para o mal. Por muitos anos, Mondain atravessou as terras de Akalabeth espalhando o mal e a morte por onde passava. Ele criou masmorras profundas, tão profundas e extensas que suas profundezas mais baixas nunca foram exploradas. Nessas masmorras, ele soltou mais mal. Ele enviou ladrões, esqueletos e serpentes para habitar perto da superfície, e demônios e balrons para guardar as profundezas. Agora o sangue corria livremente em Akalabeth, e criaturas vis logo vieram a vagar perto da superfície. Mondain lançou tanta doença e pestilência sobre Akalabeth, que homens e bestas viviam em constante medo. Assim foi a Idade das Trevas de Akalabeth."; }
			else if ( book.BookTitle == "The Lost Land" ){ book.BookText = "Embora eu mesmo tenha falhado em minha busca pelo Continente Perdido, trago a história frequentemente contada pelos menestréis que vagueiam pela terra, na esperança de que isso ajude em tua missão... Há muitos, muitos anos, vivia um povo forte e sensível que habitava o continente de Ambrosia. Esse povo desenvolveu grandes poderes sobre as forças da natureza, e correm rumores de que até mesmo o poder de mudar o ser físico estava dentro do alcance de seu conhecimento. Dessas histórias cresceram as lendas dos santuários mágicos de Ambrosia. A terra prosperou com o passar dos anos, e o estranho poder cresceu em força. Então, sem aviso, houve uma grande e violixa convulsão, e a terra afundou subitamente no mar. Um grande redemoinho puxou a terra para beneath das profundezas das águas. O redemoinho não existe mais, no entanto, muitos afirmam ter encontrado um portão lunar para a terra perdida de Ambrosia."; }
			else if ( book.BookTitle == "The Balance Vol I of II" ){ book.BookText = "Aprendi sobre os Ofidianos com o sábio na Britânia. Eles vivem na Ilha da Serpente e têm uma religião única das três serpentes que fornecem equilíbrio ao universo. Embora considerado folclore por muitos, acredito que essa religião tem base na verdade. Eles são conhecidos como as Serpentes do Equilíbrio, Ordem e Caos. Quando Exodus retirou a Serpente do Equilíbrio da Ilha da Serpente, para guardar seu castelo, o equilíbrio começou a vacilar. O Estranho libertou a Serpente, permitindo seu retorno, mas os efeitos ainda são sentidos. Caos e Ordem ainda batalham entre si no vazio, e a Ordem parece estar vencendo. O poder do Caos foi acidentalmente liberado e possuiu três pobres almas. Eles agora vagueiam pela masmorra de Bane como os Flagelos do Caos, e cada um possui uma das serpentes de rocha negra necessárias para manter o equilíbrio. Tentei matar um deles, mas falhei em minhas tentativas. Uma cigana em Lodor me disse que eu precisaria de três itens únicos se quisesse derrotar todos os Flagelos do Caos. Precisarei encontrar o Orbe da Lógica se quiser derrotar o Flagelo da Insanidade. É preciso adquirir as Escalas da Ethicalidade se esperar derrotar o Flagelo da Anarquia. Por fim, precisamos encontrar a Lanterna da Disciplina para matar o Flagelo da Dissolução. Esses itens podem estar em qualquer lugar nos reinos, mas a cigana disse para procurá-los nas masmorras. Será uma grande jornada, mas o equilíbrio deve ser mantido se quisermos sobreviver. Também fui avisado que esses itens são do vazio, então se eu conseguir encontrar um, poderia perdê-lo se outro o retirar de outro lugar. Preciso encontrar esses itens e despachar os Flagelos o mais rápido possível."; }
			else if ( book.BookTitle == "The Balance Vol II of II" ){ book.BookText = "As serpentes de rocha negra estão quase ao meu alcance. Cada uma representa as Serpentes do Equilíbrio, Ordem e Caos. Se eu quiser subjugar as Serpentes do Caos e da Ordem, precisarei ter todos os três itens para ter sucesso. Encontrei um pergaminho antigo dentro da biblioteca de Lord British, que me deu as informações muito necessárias de que precisava. Embora categorizado como lenda pelo bibliotecário, acredito que isso seja realmente verdade. Preciso encontrar a Parede de Luzes no Santuário da Serpente. Se eu me aproximar dela, aparecerei na sala deste mundo e do vazio. Devo me aproximar das estátuas da Ordem e do Caos e anunciar que estou aqui para restaurar o equilíbrio. Isso deve dar a uma das serpentes de rocha negra o poder da Serpente do Equilíbrio. Então, se eu tocar cada uma das estátuas, a serpente aparecerá neste reino onde poderei então subjugá-la. Devo fazer isso com ambas as serpentes, pois ambas devem ser subjugadas. Uma vez que suas formas de rocha negra tenham suas almas subjugadas capturadas, posso procurar a Grande Serpente da Terra e anunciar a ela que mantive o equilíbrio. Estou indo enfrentar o Flagelo da Insanidade, pois encontrei o Orbe da Lógica. Tentarei encontrar os outros dois se sobreviver à batalha que se aproxima."; }
			else if ( book.BookTitle == "The Black Gate Demon" ){ book.BookText = "Por séculos, os maiores feiticeiros tentaram alcançar o Plano Etéreo. O sucesso ainda não foi alcançado, mas minha pesquisa mais recente descobriu um pergaminho no fundo dos corredores da Masmorra da Perdição. Embora escrito em uma estranha língua drow... consegui decifrar a maior parte do seu conteúdo. Embora muitos magos invoquem a ajuda de demônios de outros mundos, um mind flayer em particular conseguiu invocar um demônio do portão negro. Acredita-se que este demônio em particular seja do Plano Etéreo. Acho que fazer um acordo com este demônio não é algo tão fácil de fazer, mas se talvez ele puder ser derrotado em batalha, um portal pode ser aberto para o lugar que busco ir. Invoquei 12 demônios até agora, e nenhum deles era um demônio do portão negro. Se eu pudesse apenas encontrar a cidade escondida dos mind flayers, talvez lá eu pudesse aprender os segredos para invocar este espírito."; }
			else if ( book.BookTitle == "The Blue Ore" ){ book.BookText = "Cadelita é um metal azul com propriedades muito interessantes. Pode filtrar energia nociva, fazer com que ataques físicos prejudiquem o agressor, é mais fácil de usar do que outras armaduras de metal laminado e, portanto, proporciona um pouco de rapidez para quem a veste. Não é um metal nativo do mundo que conhecemos e só pode ser encontrado em meteoros que caíram do céu. Encontrei um depósito desse metal raro, e rumores dizem que ele destruiu os habitantes de Ambrosia. Mesmo com minhas habilidades como mestre mineiro, não consegui escavar o minério que brilha intensamente. Ouvi contos nas tavernas sobre o lendário ferreiro conhecido como Zorn, que deixou estas terras séculos atrás e está a serviço do Cavaleiro Negro há muitas luas. Ele é conhecido por carregar uma picareta de adamantium forte o suficiente para lascar a pedra azul brilhante. Alguns até dizem que ele já foi ferreiro dos deuses. Contratei alguns mercenários para se infiltrar no cofre do Cavaleiro Negro, onde acredita-se que Zorn esteja. Se eu pudesse conseguir sua picareta dele, poderia escavar um pouco deste minério e então viajar para a Grande Forja dos Anões. Só precisarei seguir meu mapa até ela, em Lodoria. Se eu pudesse fazer uma armadura deste metal para Lord British, ele pode me pedir para me tornar um membro de sua corte."; }
			else if ( book.BookTitle == "Crystal Flasks" ){ book.BookText = "Acho que a criatura era feita de puro líquido. Ela veio na minha direção enquanto eu procurava por um artefato na Masmorra da Vergonha. Quando golpheei a besta, uma substância espessa e pegajosa voou para fora e cobriu o chão. Foi doloroso pisar, com certeza. Derrotei a criatura e decidi levar um pouco desse líquido derramado para a alquimista em Lodoria, mas as garrafas que eu tinha não conseguiam conter o fluido. Quando mais tarde contei minha história à alquimista, ela me disse que eu precisaria de alguma forma encontrar um frasco cristalino para recolher a substância e trazê-la a ela. Ela me avisou para ter cuidado se eu conseguisse um frasco cheio desse líquido estranho. Se eu o derramasse, cobriria o chão e seria tão prejudicial quanto se jorrasse do monstro de quem o obtive. De acordo com seu conhecimento, ninguém sabe como fazer frascos cristalinos e eles são muito raros de encontrar. Como eram mais comuns séculos atrás, acho que minha melhor chance de encontrar um é procurar nas masmorras da terra, pois elas contêm itens de um tempo há muito esquecido."; }
			else if ( book.BookTitle == "The Curse of the Island" ){ book.BookText = "Começou com Batlin, um druida de poderes mágicos consideráveis. Ele nasceu em Yew e cresceu com os Druidas. Quando jovem adulto, começou a viajar por toda a terra, conhecendo Elizabeth e Abraham durante esse tempo. Ele foi para Skara Brae durante esse período e perguntou a Mangar sobre as respostas da vida e da morte. Quando Batlin soube que não havia nenhuma, sua escuridão começou. Contatado pelo Guardião pouco tempo depois, ele, Elizabeth e Abraham criaram a Fraternidade em sua sede de poder, para permitir que o Guardião assumisse o controle da terra de Sosaria. Fracassando nessa missão vil, Batlin ouviu o Arquimago Zekylis falando sobre um lugar chamado Ilha da Serpente. Por ordens do Guardião, Batlin foi para a Ilha da Serpente. Ele deveria capturar as essências de seres conhecidos como os Flagelos do Caos, que o Guardião libertaria em Sosaria. Sendo faminto por poder, Batlin ia usar os Flagelos para tomar o poder para si, mas algo aconteceu e eles foram libertados de sua prisão mágica. Possuindo três dos seguidores de Batlin, os Flagelos mataram Batlin e fugiram para suas próprias áreas da Ilha da Serpente. Isso teve consequências de longo alcance, pois algumas das criaturas estavam ficando amaldiçoadas pela influência dos Flagelos. Alguns aventureiros falaram desses monstros amaldiçoados e de como eles se tornaram mais poderosos uma vez amaldiçoados. Muitos pereceram por essas bestas, mas aqueles que as derrotaram às vezes voltavam com tesouros inimagináveis. Sábios não têm ideia de quanto tempo a maldição durará e quais criaturas serão corrompidas, mas aventureiros corajosos às vezes os caçam para destruí-los. Vá bem se você encontrar essas bestas amaldiçoadas."; }
			else if ( book.BookTitle == "The Dark Age" ){ book.BookText = "Dizem que há muito tempo paz e tranquilidade cobriam as terras, comida e bebida fluíam livremente, homem e besta viviam em paz, ouro e prata abundavam. Foi a idade de ouro de Sosaria. Mondain, segundo filho de Wolfgang, um grande rei dos tempos antigos, desejou obter a herança de seu irmão e, por isso, usou seus grandes poderes para o mal. Por muitos anos, Mondain atravessou as terras de Sosaria espalhando o mal e a morte por onde passava. Ele criou masmorras profundas, tão profundas e extensas que suas profundezas mais baixas nunca foram exploradas. Nessas masmorras, ele soltou mais mal. Ele enviou ladrões, esqueletos e serpentes para habitar perto da superfície, e demônios e balrogs para guardar as profundezas. Agora o sangue corria livremente em Sosaria, e criaturas vis logo vieram a vagar perto da superfície. Mondain lançou tanta doença e pestilência sobre Sosaria, que homens e bestas viviam em constante medo. Assim foi a idade das trevas de Sosaria. Surgiu da terra um homem, puro e justo, para lutar contra o Senhor das Trevas. British, Campeão da Luz Branca, batalhou com Mondain nas profundezas do labirinto de masmorras, eventualmente expulsando-o de Sosaria para sempre. British da Luz Branca foi proclamado Lord British, Protetor de Sosaria. No entanto, muitos danos foram sofridos pelas terras. O Renascimento de Sosaria havia começado."; }
			else if ( book.BookTitle == "The Dark Core" ){ book.BookText = "Alguns dizem que veio do futuro. Uma máquina que parece mais demônio do que metal. Exodus foi um flagelo sobre a terra de Sosaria, criado pelas mãos de Mondain e Minax. Quando o estranho destruiu o ser mecânico de Exodus, o autômato demoníaco que jazia beneath foi liberado. Agora ele usa sua programação para viajar de terra em terra, nunca ficando muito tempo em um lugar. Ele vai para as tumbas e masmorras, registrando tudo o que vê dos monstros que espreitam lá dentro. Ele aprende a ser um oponente mais eficaz, com uma demonstração recente sendo o abate instantâneo de meu companheiro urso pardo. Ele possui um campo de força que pode alternar entre proteção mágica e corpo a corpo. Ele também emite feixes de energia que eletrificam a alma. Por que alguém tentaria enfrentar tal ser? É o núcleo negro que eu busco. Dentro do peito deste demônio de metal, Exodus tem um núcleo que armazena a multitude de informações que ele aprende. A informação dentro do núcleo não é o que busco, mas destruir o núcleo para liberar seu poder sim. Encontrei a antiga cidade gargula de pedra no Império Selvagem, mas ainda não encontrei a Forja da Virtude dentro, onde devo mergulhar o núcleo. Se o que os gargulas falam é verdade, um item colocado no Santuário da Diligência absorverá o poder do núcleo quando ele for destruído. Também devo falar o mantra mágico 'Vas An Ort Ailem' e jogar o núcleo na forja. Dizem que o santuário fica next to a forja, mas encontrá-lo não significa nada se eu não puder rastrear onde Exodus estará a seguir. As terras são tão vastas que encontrá-lo se mostrará bastante difícil. O tempo é essencial. Mesmo que eu consiga o núcleo negro, tenho muito pouco tempo antes que Exodus se reconstrua e o núcleo saia de minha posse e retorne ao seu peito. Me pergunto se alguma coisa pode destruir esta máquina infernal."; }
			else if ( book.BookTitle == "Death to Pirates" ){ book.BookText = "Alguns acreditam que quando um navio está para ser engolido pelo mar, as almas daqueles a bordo também são reivindicadas por ela. Servi no Blue Wave por muitos anos. Levávamos carga da Cidade de Lodoria para portos distantes como Colinas Glaciais ou Springvale. Um dia frio, íamos levar uma caixa incomum para uma ilha no extremo sudoeste de Lodor. Não sabíamos de um assentamento lá, mas o ouro era bom e zarpamos. Esta ilha tinha a aparência e sensação do mal puro. Um velho a bordo nos contou histórias de piratas que vieram a esta ilha por um refúgio seguro, mas foram amaldiçoados para viver entre os mortos que vagueiam pelos bosques. As montanhas eram escuras, o solo era lama e as árvores estavam enegrecidas como se queimadas. Uma figura pálida se aproximou de nós no cais e tomou posse da caixa. Suas mãos eram brancas como osso limpo e sua voz tinha um som assustador. Ele nos jogou um saco com o ouro restante e seguimos nosso caminho. Zarpamos o mais rápido possível de volta para casa. Mal havíamos saído da vista daquele lugar quando um navio veio em nossa direção do leste. A madeira era de um branco fantasmagórico e podíamos distinguir alguns arrastos pelo convés. À medida que o navio se aproximava, o horror se tornava mais real. Esta era uma barcaça dos mortos. Eles embarcaram em nosso vessel e mataram quase todos os homens a bordo. Eles não levaram nenhum saque, mas instead afundaram o Blue Wave no mar. Apenas Vrendora, Selena e eu sobrevivemos. Ficamos flutuando no mar por dias até que a Capitã Feldora nos resgatou em seu navio, o Velvet Sky. Após nosso retorno ao Porto do Crepúsculo, Vrendora enlouqueceu e foi morta pelos guardas locais. Selena conseguiu seu próprio navio e tripulação e ouvi dizer que ela procura o mar por aquele navio. Decidi passar meus anos restantes em Springvale, trocando histórias por hidromel. Contos do mar e de como há mais a temer lá fora do que krakens."; }
			else if ( book.BookTitle == "The Death Knights" ){ book.BookText = "Ele foi o primeiro dos Cavaleiros da Morte, trazido para o serviço pelo Senhor Demônio conhecido como Brazuul. Esse foi o dia em que Kas, o Bondoso, foi para sempre conhecido como Kas, o das Mãos Ensanguentadas. Ele espalhou terror por toda Sosaria e Lodoria, no caminho atraindo outros 14 para sua busca insana para livrar o mundo da ordem da lei. Um grupo de Paladinos os perseguiu de um extremo ao outro do mundo, derrotando cada um quando encontrado. Kas colocou cada discípulo para descansar no fundo de várias masmorras, na esperança de que sua tumba fosse deixada intocada. Muitos acreditam que esses contos são usados para assustar crianças para que não saiam da segurança de suas aldeias, mas encontrei pistas que levam ao Túmulo de Kas em Sosaria em um mapa antigo que encontrei na ilha de Drácula em Lodoria. Acredita-se que os Cavaleiros da Morte frequentemente construíam suas fortalezas lá, junto com os necromantes da terra. Este mapa leva às montanhas, mas estou curioso sobre o verso do mapa. Escrito em sangue estão as palavras 'Mortem Mangone'. Não tenho certeza do que significam, mas em breve posso conseguir o livro e a lanterna de Kas e começar a aprender os caminhos do Cavaleiro da Morte. Se minha pesquisa estiver correta, um Cavaleiro da Morte pode ter apenas um livro e uma lanterna. Obter qualquer outro faria com que o anterior desaparecesse. Acho que essa era a maneira como Kas mantinha seus súditos leais limitados aos 14 que ele mesmo escolheu. Serei digno? Minhas ações recentes foram vis o suficiente para chamar sua atenção? Talvez eu deva aprender um pouco sobre cavalaria com um mestre de guild guerreiro em Umbra ou Ravendark, ou Kas pode não atender ao meu chamado."; }
			else if ( book.BookTitle == "The Darkness Within" ){ book.BookText = "Seu nome era Drácula, e ele já foi um Barão na terra de Sosaria. Embora um homem bom, a raiva e o ódio o levaram para os braços da escuridão. Drácula foi outrora o governante da cidade de Montor. Eles desfrutaram de anos de paz, pois Drácula construiu muralhas ao redor da cidade, protegendo-a de quaisquer perigos lá fora. Uma noite, um assassino escalou as muralhas e assassinou a esposa de Drácula em seu sono enquanto ele visitava Britain. Após o retorno de Drácula, ele trancou-se em seu quarto por semanas. Uma noite, testemunhas o viram sair furtivamente da cidade. Um dos guardas foi alertado e seguiu o Barão, apenas para perdê-lo quando ele entrou na Masmorra da Perdição. Foi meses depois, quando Drácula foi avistado na vila de Grey. Era tarde da noite e ele estava mordendo o pescoço da costureira local, aparentemente bebendo seu sangue. Os guardas chegaram tarde demais para prendê-lo por seus crimes. Esses avistamentos continuaram de cada assentamento conforme as noites iam e vinham. Alguns acreditavam que ele procurava o assassino que matou sua esposa. Outros acreditavam que ele estava amaldiçoado pelos vampiros e apenas buscava sangue dos vivos. Lord British liderou um grupo de seus melhores guardas para caçar Drácula e acabar com sua sede de sangue. Eles o perseguiram pela noite, viajando para o sul de Britain. Drácula buscou santuário na Torre do Lich e nunca mais foi visto."; }
			else if ( book.BookTitle == "The Destruction of Exodus" ){ book.BookText = "Após o fim de Mondain e Minax, o povo de Sosaria pensou que o pior havia passado... mas o pior ainda estava por vir. Exodus, seu descendente e criação... nem completamente demônio nem máquina... queria vingança pela destruição de seus criadores. Iniciando uma campanha de terror, ele ergueu uma ilha do mar e então ameaçou rasgar Sosaria com seus poderes e exércitos do mal. O Estranho retornou pela terceira vez para salvar o mundo deste novo mal. Desta vez, no entanto, o herói tinha três companheiros para sobreviver contra as hordas de Exodus. Juntos, eles viajaram pela terra, recuperaram informações, antes de encontrar as Quatro Cartas nas terras perdidas de Ambrosia. Com a ajuda do Senhor do Tempo, o grupo foi capaz de aprender o que fazer para derrotar Exodus. Após recuperar as Armas Exóticas e a Armadura Exótica, eles estavam prontos para confrontá-lo. Na Ilha do Fogo, eles primeiro contornaram a Grande Serpente da Terra e então lutaram contra os lacaios de Exodus, até finalmente chegarem ao núcleo... a parte do Exodus que era um computador. Inserindo as cartas, a máquina explodiu e Exodus deixou de existir. Agora o castelo de Exodus está em ruínas. Aqueles que ousaram explorá-lo afirmaram que demônios e mortos-vivos vagueiam pelos corredores beneath da fortaleza arruinada. Alguns ainda ousam entrar, pois acredita-se que riquezas estejam dentro."; }
			else if ( book.BookTitle == "The Knight Who Fell" ){ book.BookText = "A cavalaria é uma busca nobre que se assume para trazer luz a uma terra de escuridão. Males desconhecidos andam à solta e esses cavaleiros são os defensores da paz que desfrutamos neste mundo. O poder de um cavaleiro é frequentemente concedido devido à sua generosidade. Quando eles destroem o mal, muitas vezes encontram riquezas que são demais para guardar para si mesmos. Eles pegariam parte dessa riqueza e a deixariam em santuários, altares ou estátuas de deusas. Então os padres recolheriam esse ouro e o distribuiriam entre os pobres e menos afortunados. Um cavaleiro não acreditava neste mantra. Ele queria toda a riqueza que pudesse coletar, muitas vezes matando outros pelas deles. Sua alma estava tão corrompida, que seus poderes de cavalaria foram lentamente escurecidos e distorcidos em algo pútrido e maligno. Ele vestiu uma armadura negra e aterrorizou vilas e cidades para tomar o que elas tinham. Cavaleiros foram enviados para eliminar este traidor da fé, mas muitos morreram. Lord British reuniu um exército liderado por seu maior cavaleiro para encontrar este cavaleiro negro. Eles o perseguiram até a misteriosa ilha de Umber Veil. A vila de Renika estava queimando quando o exército chegou. Muitos dos sobreviventes estavam barricados na igreja nearby, enquanto outros se trancaram no castelo da montanha. Eles disseram ao exército que o cavaleiro negro fugiu para a Ilha da Serpente. O exército desistiu da perseguição, já que o cavaleiro negro não mais aterrorizaria suas terras. Eles ajudaram Renika a se levantar novamente e então voltaram para casa. Isso foi há muitos, muitos anos. Ninguém viu o cavaleiro negro em Sosaria desde então. Houve rumores nas tavernas ao longo dos anos. Alguns afirmaram ter navegado até a Ilha da Serpente e encontrado uma ilha onde o cavaleiro negro construiu sua fortaleza. Alguns até afirmaram que ele tem o maior cofre subterrâneo que já viram. Tudo o que o cavaleiro negro já tomou supostamente está lá embaixo, junto com aqueles encarregados de guardá-lo. Acho que essas histórias são exageradas, pois aqueles que contam essas histórias não têm nada para mostrar do cofre. Devemos apenas ficar felizes que ele se foi, para sempre."; }
			else if ( book.BookTitle == "The Fall of Mondain" ){ book.BookText = "Sosaria precisava de um herói inabalável, alguém que enfrentaria perigos horríveis de se considerar. Uma praga havia caído sobre o reino, um flagelo estava sobre a terra! As aldeias estavam devastadas, montes arruinados de cinzas onde outrora pisaram camponeses de coração forte e mente sã, onde outrora havia campos de grãos e frutas, onde gado e aves engordavam com as farturas de Sosaria. Todo tipo de criatura perversa e vil predava o povo e devastava a terra. É obra de alguém tão malévolo que o próprio solo tremia ao ouvir seu nome. Mondain, o feiticeiro, fez bem sua malícia. Os nobres discutiam entre si, e cada um se recolheu aos confins de sua fortaleza na esperança de assistir a queda de seus rivais. Verdadeiramente, o Perverso acumulou indignidade sobre maldição, liberando sobre o reino uma hoste de criaturas e bestas tão sanguinárias e perversas que o povo indefeso caiu como grãos diante da foice do ceifador. Esses habitantes do underworld detinham o controle sobre tudo que se podia avistar, exceto pelas fortalezas dos nobres embriagados com sua própria ambição. Em nenhum lugar do outrora pacífico país um viajante podia encontrar passagem ou pouso seguros, exceto nas fortalezas dos autoproclamados reis... e eles exigiam trabalhos pesados por seus favores. Apenas o jovem Lord British permaneceu firme na visão de uma Sosaria pacífica e unida. Em seu castelo e sua cidade, os puros de coração encontraram um aliado e reabastecimento para as necessidades daquele que escolheu lutar pelo reino. Ele ajudou a livrar a terra do flagelo que a acometera. Sem sua ajuda, Sosaria certamente teria perecido diante do ataque do necromante maléfico."; }
			else if ( book.BookTitle == "Forging the Fire" ){ book.BookText = "A dobragem do aço é algo feito há séculos, mas antes da ascensão do homem... alguém forjava com o poder do fogo vulcânico. Dizem que Purslos era um gargula e um excelente artesão, que não só conseguia moldar o aço à sua vontade... mas também aprimorá-lo com o poder do magma da ilha. A lenda conta que Purslos fez uma espada para seu mestre, Tuxluka. Diziam que a espada era de fogo sólido e queimava tanto quanto cortava. Tuxluka usou esta adaga para vencer a guerra Ofidiana e trazer paz à Ilha da Serpente. Um dia podemos aprender os segredos deste método de ferraria. Seja fábula ou fato, as histórias são abundantes demais para ignorar."; }
			else if ( book.BookTitle == "Forgotten Dungeons" ){ book.BookText = "Passei minha vida procurando ouro, gemas e joias. Embora tenha encontrado muito, o sangue sempre foi derramado no caminho. Camaradas caíram, inimigos foram derrotados, agora vivo a vida de reis. Não precisei construir grandes castelos ou reinos na terra. Não precisei governar uma vasta extensão para ostentar minha riqueza. Simplesmente peguei o que ganhei e vivo aqui agora em seus corredores agora iluminados. Estive em muitas masmorras. Umas grandes, outras pequenas. As pequenas eram rápidas de procurar, com certeza. Um dia, quando um velho mago me acompanhava, procuramos uma pequena masmorra por algo de valor. Não tinha nada, mas as criaturas dentro eram muitas e foram abatidas sem esforço. Cansados da viagem do dia, decidimos acampar durante a noite dentro das salas escuras deste lugar. Foi quando o mago mencionou que este seria um bom lar, se alguém tivesse o ouro para contratar mãos para limpá-lo e fortificar as paredes. O mago não fazia ideia do ouro que eu tinha nos muitos bancos da terra, mas achei sua ideia bem pensada. Voltamos para Devil Guard no dia seguinte e nos separamos. Viajei para Moon e contratei muitos homens para tornar este lugar minha casa. Limpei muitas masmorras em meu tempo, mas esta é a minha favorita."; }
			else if ( book.BookTitle == "The Cruel Game" ){ book.BookText = "Os assuntos dos deuses podem ser maçantes para aqueles que compartilham os tronos de tal poder, tão maçantes que alguns deles decidiram apostar na queda dos mundos. Os deuses da chama, da doença, do poder e do gelo fizeram um acordo que determinaria qual mundo cairia dos dons concedidos a eles. Eles decidiram cada um construir uma forja mística em terras diferentes e simplesmente sentaram e observaram os eventos se desenrolarem. O deus da chama construiu sua forja na Ilha da Serpente. A forja era tão quente... que rasgou um buraco na terra. A deusa da doença construiu sua forja na floresta mais bonita do Império Selvagem, que acreditava-se ser tão venenosa... que transformou a área ao seu redor em um pântano doentio. O deus do poder construiu sua forja no mundo de Ambrosia, onde eventualmente foi adorada pelos habitantes e santuários foram construídos em sua homenagem. O deus do gelo construiu sua forja na região tropical de Lodoria, que acreditava-se ser tão fria... que transformou toda a selva em uma tundra invernal. Os deuses escolheram um campeão cada um dessas terras e falaram com eles em seus sonhos. A cada um foi dada a localização das forjas, junto com instruções sobre como usá-las. Eles simplesmente tinham que colocar armas e armaduras nas lajes de pedra ao redor da forja. Uma vez que dissessem seus próprios nomes, os itens seriam infundidos com o poder das forjas mágicas. Eles deveriam espalhar essas armas e armaduras para seus camaradas para proteção ou guerra. Os deuses então deixaram esses campeões para seu trabalho. A primeira terra a cair concederia àquele deus o vencedor do concurso. Os anos passaram e vidas foram perdidas para as armas forjadas. Algumas dessas batalhas podem ser lidas em textos antigos. Alguns acreditam que a Ilha da Serpente caiu, pois contos sobre a superfície são vazios de civilização. Outros pensam que Ambrosia foi a que fez da deusa da doença a vitoriosa do concurso, pois acreditava-se ter sido totalmente destruída pelo poder das armas de energia forjadas. A lenda tem sido contada de geração em geração. Ninguém encontrou essas forjas nem aprendeu os nomes dos campeões escolhidos para este jogo cruel. Será para sempre um mistério."; }
			else if ( book.BookTitle == "The Ice Queen" ){ book.BookText = "O conto que escrevo não é de forma alguma uma fábula, e aconselho a não tratá-lo como tal. Seu nome vem em muitas formas. Não vou adivinhar o que pode ou não ser. Ela nasceu dentro do Culto do Sangue que habita a maior das ilhas nas Ilhas do Pavor. Ela nasceu com a pele da cor da neve e olhos que pareciam perfurar a carne quando fitavam você. Aqueles que a olhavam lembravam-se de contos sobre tal garota, que nasceria e realizaria algo grandioso. Ninguém tinha certeza do que era, mas os muitos tomos do culto foram consultados. Levou anos para ler através de pergaminhos, papiros, tabuletas e livros. Ela tinha apenas 14 anos quando encontraram um pergaminho que falava de sua vinda. A profecia escrita afirmava que ela destruiria o culto e baniria a Deusa do Sangue de volta ao reino dos demônios. Decidiram que ela seria morta antes que qualquer coisa disso viesse a ser. Eles a arrastaram para o altar, amarraram-na a ele e invocaram o demônio que levaria sua alma para o underworld. Quando o demônio foi para agarrá-la do altar, ela gritou. Seu grito foi alto e fez os animais da selva fugirem em terror. O grito congelou o demônio em um bloco de gelo, que então se estilhaçou em muitos pedaços ao seu redor. Seus laços também congelaram a ponto de desmoronarem quando ela puxou. Ela ficou de pé em cima do altar e gritou com os seguidores que vieram testemunhar seu desaparecimento. Muitos escaparam, mas muitos sofreram o mesmo destino do demônio momentos antes. Ela fugiu para a ilha tropical ao norte com nada além de uma pequena jangada. Ela encontrou uma caverna lá onde se abrigou por dias, comendo raízes e frutas silvestres que colhia. À medida que envelhecia, seu poder também crescia. A ilha foi lentamente transformada em uma tundra congelada. A caverna onde ela vivia tinha paredes de gelo, construindo corredores suaves. Ela construiu magicamente golems de gelo puro para patrulhar seus corredores. Agora ela senta em sua sala do trono, planejando o culto que está destinada a destruir."; }
			else if ( book.BookTitle == "Luck of the Rogue" ){ book.BookText = "A sorte é um dos enigmas cósmicos que magos e sábios parecem não conseguir compreender. Nem magia nem intervenção divina, a sorte é a personificação do caos. Você pode ter má sorte ou boa sorte. Pode-se enriquecer com a sorte encontrando itens mágicos que parecem ter tido a pata de coelho esfregada neles. Eu mesmo pareço ser abundante em sorte, mas o que significa ter sorte neste reino? Os outros aventureiros com quem viajo não parecem encontrar os objetos maravilhosos que encontrei, seja abatendo bestas poderosas ou encontrando tesouros perdidos. Isso os enfurece, com certeza. Também pareço conseguir evitar armadilhas às vezes, onde meus camaradas não conseguiram. Não vou mentir, mas a separação de nosso butim é um grande benefício durante tais infortúnios. Então não sei o que traz sorte a alguns e não a outros, mas acho que sou mais próspero por causa disso."; }
			else if ( book.BookTitle == "A Tattered Journal" ){ book.BookText = "- 3º do Outono - Foi há décadas, mas a memória queimada faz parecer que foi ontem. A cidade inteira foi queimada até o chão por aquele dragão poderoso, e minha família com ela. Eu o cacei por anos, nunca encontrando um vestígio dele. Cinco anos atrás, ouvi um guarda bêbado balbuciando na taverna sobre um mago que capturou a besta e a selou dentro de um orbe de cristal. Eles não conseguiram derrotar a criatura, então escolheram este curso para garantir que Sosaria estivesse segura. Embora eu aplaudisse o mago, a vingança me foi roubada. - 20º do Outono - Descobri quem era o mago e fui vê-lo em Montor. Quando cheguei lá, a notícia era que ele encontrou seu fim ao procurar por textos antigos no fundo da Masmorra das Pistas. Antes que seu irmão pudesse chegar a Montor para reivindicar os pertences do mago, eu me infiltrei na casa e roubei o orbe. Eu podia ver o dragão preso dentro dele, mas tenho muito trabalho a fazer se quiser abri-lo. - 42º do Outono - Tenho os poucos diamantes de que preciso, junto com as raízes de mandrágora. Não sei como, mas olhar para o orbe por tempo suficiente me mostrou os vários itens de que preciso para ajudar a quebrar o feitiço. Estou indo comprar uma capa de pele, pois preciso encontrar agora a chifre dos infernos congelados. - 70º do Outono - Mal sobrevivi, mas finalmente consegui o olho das pragas. Estou descansando na estalagem aqui em Springvale, e ficarei aqui por alguns dias para permitir que minhas feridas curem. Por que sei disso, não tenho certeza, mas preciso levar esta prisão de cristal para a Masmorra Destard. Acho que é aqui que o mago prendeu o dragão e, portanto, precisa ser libertado na mesma área. - 5º do Inverno - Falhei. Libertei a besta de sua gaiola mágica e não consegui matá-la. A batalha foi longa e precisei correr e me esconder em um ponto. Quando voltei, o dragão havia desaparecido. Receio nunca ter minha chance de vingança, mas continuarei procurando. Procurarei até que não reste vida dele ou de mim."; }
			else if ( book.BookTitle == "The Curse of Mangar" ){ book.BookText = "Há muito tempo, quando a magia ainda prevalecia, o malvado feiticeiro Mangar, o Sombrio, ameaçou uma pequena mas harmoniosa cidade chamada Skara Brae. Criaturas malignas vagavam beneath de Skara Brae e se juntaram ao seu domínio das sombras. Mangar cercou Skara Brae em um feitiço de Morte Anulada, isolando totalmente Skara Brae de qualquer ajuda possível. Então, uma noite, todos os milicianos da cidade desapareceram. Apenas aqueles que estavam dentro da cidade sabem deste destino. Outros em Sosaria não veem nada além de uma ilha cheia de ruínas que outrora foi Skara Brae. Este era o plano de Mangar o tempo todo. Ele queria que todos pensassem que Skara Brae estava destruída, para que ninguém viesse se opor a ele. O futuro de Skara Brae pende na balança. Não sobrou ninguém para resistir. Apenas um punhado de jovens guerreiros inexperientes, magos juniores, alguns bardos mal velhos o suficiente para beber e alguns ladrões desempregados. Eu estava lá. Eu era o líder de um grupo irregular de lutadores pela liberdade. Tentamos derrotar Mangar, mas ele é poderoso demais. Logo quando pensamos que o tínhamos, ele desapareceu em uma nuvem de fumaça, proclamando que retornaria. Isso foi o suficiente para enfraquecer a magia da Morte Anulada. Um portal se abriu, mas apenas por um curto período. Entramos no portal e voltamos para Sosaria, aparecendo no topo de uma torre que Mangar havia construído lá. Atenção, esta torre permite que Mangar viaje entre Skara Brae e Sosaria. Se alguém não tiver cuidado, pode tocar a bola de cristal que o prenderia em Skara Brae."; }
			else if ( book.BookTitle == "The Times of Minax" ){ book.BookText = "O Estranho não tinha a tarefa de salvar Sosaria, mas instead a Terra da Feiticeira Minax. Sendo a amante e aprendiz de Mondain, ela estava bastante zangada com sua morte pelas mãos do Estranho e jurou vingança. Manipulando a linha do tempo para este fim, ela deixou a Terra morrer em um holocausto atômico em 2111 - toda a vida na Terra pereceu no rescaldo. O Estranho, tendo escapado das mudanças na linha do tempo no último momento, teve que decifrar o mistério dos Portões do Tempo, que permitiam a viagem no tempo, para alcançar Minax e impedir que aqueles eventos horríveis acontecessem. Reunindo a única arma que poderia matar Minax, a Espada Rápida Enilno, e vestindo a proteção do Anel do Campo de Força, o Estranho viajou de volta ao Tempo das Lendas e confrontou Minax em seu castelo para matá-la. Com sua morte, a linha do tempo voltou ao normal, com ninguém lembrando dos horríveis eventos que ocorreram na linha do tempo alterada... todos exceto o Estranho e eu."; }
			else if ( book.BookTitle == "Rangers of Lodoria" ){ book.BookText = "Os rangers da terra dos homens rastrearam elfos negros de volta à sua terra natal. Pensando que o mundo de Lodoria estava contaminado com essas fadas malignas, os rangers partiram para livrar o mundo delas. Suas muitas luas de caça levaram a um encontro com os elfos da superfície, que retratavam uma presença mais benigna com a qual os rangers estavam familiarizados. Este foi o início de uma aliança entre os rangers e os elfos de Lodoria, onde livrar o mundo do mal era a guerra silenciosa travada acima e beneath da superfície. Os rangers construíram seu forte nas montanhas perto da Cidade de Lodoria, que parece ser alcançável apenas por uma caverna tão negra quanto a pele dos elfos negros. Alguém certamente se perderia dentro, mas alguém do posto avançado dos rangers poderia encontrar o caminho down da montanha e assim aprender o caminho de volta para cima. Embora os druidas transportassem magicamente os rangers para o topo da montanha, as lendas contam de um grande salão conhecido como Submontanha que foi selado há muito tempo e assim abandonado. Se eu pudesse encontrar o caminho para a Submontanha, posso estar logo beneath do posto avançado dos rangers. Vou começar minha busca naquela caverna logo ao norte do meu acampamento. Aquele infestado de lagartos e cobras."; }
			else if ( book.BookTitle == "Gem of Immortality" ){ book.BookText = "Quando a Gema da Imortalidade foi estilhaçada pelo Estranho, três fragmentos dela desapareceram. Cada um dos fragmentos se opunha a um dos princípios de verdade, amor e coragem. Os fragmentos acabaram em Ambrosia e foram perdidos até que o navio 'The Ararat', sob o comando do Capitão Johne, foi sugado pelo redemoinho. Johne encontrou os fragmentos e eles o levaram à loucura temporária. Ele matou seus três companheiros, e seu sangue caiu sobre os fragmentos. Deles, nasceram os Senhores das Sombras - Astaroth, o Senhor das Sombras do Ódio. Faulinei, o Senhor das Sombras da Falsidade. Nosfentor, o Senhor das Sombras da Covardia. Eles não perderam tempo em espalhar seu mal por todas as terras e tomaram o castelo élfico de Stonegate como seu covil. Se eu quiser reconstruir a gema, preciso obter esses fragmentos dos Senhores das Sombras. Tentei matá-los, mas eles se recusam a perecer, pois a essência da imortalidade corre dentro deles. Precisarei encontrar a Vela do Amor para matar Astaroth, o Livro da Verdade para destruir Faulinei e o Sino da Coragem para derrotar Nosfentor. O problema que enfrento é que esses itens podem estar em qualquer masmorra nos reinos. Não tenho escolha a não ser procurá-los. Eles não são deste mundo e alguém poderia recuperá-lo novamente. Se isso acontecer, então o que possuo simplesmente desaparecerá de minhas mãos. Quando encontrar um, devo rapidamente cumprir seu propósito. Contanto que alguém do meu grupo segure o item, podemos matar o Senhor das Sombras e então obter o fragmento deles. Quando finalmente conseguir todos os três, precisarei encontrar o túmulo do Rei Wolfgang e falar as mesmas palavras que ele usou para construir a gema, 'Cryst An Immortalis'. Ouvi dizer que ele foi enterrado em Britain, mas ninguém sabe onde ele jaz. O tempo é essencial, pois quem construir a gema primeiro fará com que todos os fragmentos desapareçam. A gema é importante demais para se perder com o atraso."; }
			else if ( book.BookTitle == "The Gods of Men" ){ book.BookText = "A superstição e a magia governam as terras, não os reis. Não importa para onde eu viaje, os homens seguem os deuses que conhecem e aqueles com quem cresceram com contos de feitos e poder. Embora eu não acreditasse no conceito de divindades, a história que estou prestes a contar é verdadeira. Ouvi rumores de pergaminhos mágicos contidos nos salões da Perdição. Esses contos eram difíceis de resistir, pois muitos homens contaram a mesma história. A chance de contarem a mesma mentira é pequena, então fiz meu caminho para o sul para procurar por mim mesmo. Pensei que as câmaras estariam vazias de vida, mas depois fui cercado pelas mais infernais das criaturas. Minhas palavras místicas não foram rápidas o suficiente quando um esqueleto enfiou sua cimitarra nas minhas costas. Encontrei-me de pé, olhando para o meu corpo impalado. As criaturas não me atacaram, nem meu corpo sem vida. Tentei escapar pela porta, mas não consegui tocá-la. Minhas mãos passaram por ela. Passei pela madeira grossa e cheguei à superfície da terra. Tudo parecia cinza para mim. Todos os tipos de criaturas da floresta não reagiram à minha presença. Senti-me atraído por algo. Não tinha certeza do que era, mas segui esse sentimento que tive. Ele me levou a um antigo santuário na floresta. Era um pequeno pilar de pedra. Na frente dele havia vários itens que os adoradores deixavam para o deus cujo nome estava gravado na rocha. Então ouvi uma voz de cima. Não pude ver quem estava falando, mas a voz ecoou alto em meus ouvidos. Quem quer que fosse, eles se ofereceram para me trazer de volta à terra dos vivos. Foi então que percebi que estava morto. Eles pediram apenas um pequeno sacrifício de minha riqueza para mostrar que há mais na vida do que mero ouro. Aceitei alegremente, pois não estava pronto para deixar este mundo. Encontrei-me, inteiro, na frente do santuário. As cores voltaram à minha visão e pude sentir a grama sob meus pés descalços. Voltei para Montor e peguei alguns suprimentos no banco. Voltei para a Perdição e usei uma poção de invisibilidade para me esgueirar. Encontrei onde caí em batalha, meus pertences ainda espalhados. Peguei o que pude carregar e saí rapidamente antes que o efeito da poção acabasse. Encontrei muitos desses santuários desde então. Alguns parecem ankhs, enquanto outros são estátuas de mulheres bonitas. Uma vez também encontrei um altar em uma caverna. Às vezes vejo cavaleiros deixando o ouro que encontraram nesses santuários. Ninguém o leva, pois certamente seriam amaldiçoados se o fizessem. Agora acredito nos deuses, pois eles falaram comigo."; }
			else if ( book.BookTitle == "Castles Above" ){ book.BookText = "Pensei que fosse uma nuvem de tempestade solitária à distância. Quando nenhuma chuva ou trovão veio, minha atenção foi atraída ainda mais. Era um castelo, alto acima do solo. Continuei observando para ver se ele cairia, mas ele nunca vacilou. Decidi me aproximar dele e tentar ficar abaixo dele. Foi quando encontrei a lanterna mágica azul. Dentro de seu brilho havia uma corda que ascendia aos céus. Usei toda a minha força e subi a corda, finalmente alcançando o castelo acima. Bati em sua porta de madeira grossa, e um eco ecoou de dentro. Na terceira batida, a porta se abriu um pouco. Era difícil de abrir porque era velha, empenada e provavelmente não era aberta há muitos anos. O interior do castelo era empoeirado e vazio de vida. Os corredores e salas estavam vazios de qualquer tesouro. Se eu tivesse o ouro para mobiliar este lugar, faria dele minha casa. Me pergunto que tipo de mago abandonou tal lar? Eles viveram aqui por anos, apenas para voltar à superfície e viver entre os outros?"; }
			else if ( book.BookTitle == "Staff of Five Parts" ){ book.BookText = "Lendas dizem que era poderoso demais. Dizem que Merlin foi morto por alguém que o empunhava. O Cajado do Poder Supremo foi quebrado em cinco partes pelos deuses, onde foram dados a guardiães para proteção. Se alguém se provar digno perante o Senhor do Tempo, um dia poderá montar o cajado, pois ele era o supervisor dos guardiães. As peças só podem ser montadas next to ao núcleo derretido da Lua, onde deve-se sentar no trono de pedra e falar as palavras que montarão o poder. O núcleo é onde ninguém poderia sobreviver, mas se alguém permanecer no caminho marcado pela runa, estará seguro do calor. O cajado se ligará àquele que o montar, onde nenhum outro pode empunhá-lo. O cajado aparecerá em um cajado de feitiçaria, um cajado de necromancia ou um cajado de elementalismo. Isso dependeria de qual magia é mais forte naquele que se senta no trono e fala as palavras. Ainda não encontrei as palavras para falar, e outros eventos me levaram a aprender que o quinto guardião escapou do reino do Senhor do Tempo. Xurtzar, de energia demoníaca, escapou, então apenas quatro permanecem sob os cuidados do Senhor do Tempo. Ninguém sabe o que aconteceu com Xurtzar, pois ele abriu um portão lunar para a Ilha da Serpente e fugiu. Então agora me sento e tento pensar. Para onde Xurtzar fugiu? Onde posso encontrar as palavras para falar? Devo me tornar o mago mais poderoso de Sosaria. Devo, se quiser derrotar Mangar, o Sombrio."; }
			else if ( book.BookTitle == "The Story of Exodus" ){ book.BookText = "Ninguém em toda Sosaria, nem mesmo o Estranho, poderia ter percebido que, ao acabar com as vidas de Mondain e Minax, o Estranho estaria orfanando seu único filho. O nome dessa criança incomum era Exodus, e ele não era nem máquina nem humano. Exodus surgiu do fundo do Grande Oceano para realizar uma campanha de vingança e destruição contra a terra de Sosaria. Tão terríveis foram as forças desencadeadas por Exodus que o herói que viríamos a conhecer como o Estranho precisou da assistência de um ser misterioso conhecido como o Senhor do Tempo para detê-las. E assim foi que o Estranho lidou com Exodus de maneira semelhante à que lidou com sua mãe e pai. Desde aquela época, muita especulação foi dada ao potencial incalculável de bem que uma criatura como Exodus poderia ter trazido à terra se tivesse sido persuadida a se tornar benéfica, mas desejo discordar formalmente daqueles que dizem que o Estranho deveria ter lidado com a situação de maneira diferente."; }
			else if ( book.BookTitle == "The Story of Minax" ){ book.BookText = "O triunfo do Estranho não durou muito, pois ao matar Mondain ele trouxe a ira de Minax sobre a terra. Minax era a jovem amante de Mondain e uma feiticeira com poderes mágicos ainda maiores que os de Mondain. Ela tinha o poder de comandar legiões de criaturas vis, e em sua busca por vingança pela morte de seu amante, ela trouxe muita miséria ao povo da Terra. Mais uma vez o herói que viria a ser conhecido como o Estranho, assumiu a luta, pois a Terra era seu mundo natal. O Estranho matou os lacaios de Minax e eventualmente a destruiu também. Embora tenha havido especulações sobre as motivações do Estranho, não há evidências suficientes para mostrar que o Estranho foi levado à violência por ciúmes do envolvimento romântico de Mondain com Minax. Dito isso, tais teorias são aqui denunciadas e não devem ser consideradas."; }
			else if ( book.BookTitle == "The Story of Mondain" ){ book.BookText = "O início da Primeira Era das Trevas foi marcado pela vinda de um feiticeiro chamado Mondain. O pai de Mondain se recusou a compartilhar seu segredo da imortalidade com seu filho, e suas disputas levaram à morte do pai. Atormentado pela angústia e sem dúvida por seus medos de perseguição, Mondain voltou seus poderes sombrios contra os reinos de Sosaria. Em desespero, Lord British chamou um campeão para se levantar em defesa do reino. O herói que respondeu ao seu chamado muitos anos depois viria a ser conhecido como o Estranho. Foi através das ações deste Estranho que a gema maligna do poder de Mondain foi estilhaçada e o próprio Mondain chegou a um fim muito triste, de fato."; }
			else if ( book.BookTitle == "The Bard's Tale" ){ book.BookText = "A canção que canto contará a história de um dia frio e de inverno. De muralhas de castelo e salões iluminados por tochas e um preço que os homens tiveram que pagar. Quando o mal fugiu e homens corajosos sangraram, o Sombrio veio para ficar. Pois os homens de outrora, por sangue e ouro, resgatarão Skara Brae."; }
			else if ( book.BookTitle == "Death Dealing" ){ book.BookText = "Tenho pena daqueles que temem a morte. Pode haver grande poder se você encarar o olhar do Ceifador, mas a maioria não consegue realizar tal feito. Muitos sentem que este curso não passa de práticas malignas e wretched. Toda criatura tem uma essência que pode ser aproveitada após a morte. Nós apenas aprendemos a ganhar poder com ela. Também aprendemos feitiços que exigem coisas menores como pó de sepultura ou ferro de porco. Quando as pessoas não entendem tais coisas, elas têm medo disso. Foi isso que expulsou a maioria de nós das cidades e aldeias. Não importa, é mais fácil praticar tais magias na ausência de luz. Os anciãos viram isso séculos atrás e construíram sua cidade de Umbra dentro das montanhas vulcânicas de Sosaria. Se alguém puder encontrá-la, pode praticar essas artes sem o escrutínio dos outros. Chocaria alguém olhar para ela pela primeira vez, pois aqueles que viveram lá a vida toda têm a carne tão pálida quanto os ossos dos mortos. Alguns de nós até construímos nossas fortalezas dentro dos salões montanhosos de rocha enegrecida. É um tempo glorioso para estar morto, contanto que não seja eu."; }
			else if ( book.BookTitle == "The Orb of the Abyss" ){ book.BookText = "O Underworld é um lugar incomum para nossa ordem. Embora eu tenha ouvido contos de necromancia e magias sagradas funcionando nas profundezas escuras daquele abismo, acho que meus feitiços de magia falham com muita frequência para que minhas viagens sejam relativamente seguras lá. Até meus pergaminhos e varinhas de magia parecem falhar com muita frequência. Aqueles que habitam lá, parecem não ter obstáculos em liberar feitiços de magia. Se eu quiser perseguir os titãs abaixo, precisarei estar em meu pleno potencial. Contos falam do Codex da Sabedoria Suprema, que qualquer um que segure o livro não terá tanta dificuldade com a magia. Isso, no entanto, está muito além do meu alcance, pois dizem estar em algum lugar no Vazio Etéreo. Meu próximo destino, então, é a masmorra de Hythloth, onde minha pesquisa mostrou que o Orbe do Abismo está à espera. Magos que seguram este orbe são capazes de lançar seus feitiços de magia quando estão no Underworld. Lendas até contam de magos de séculos atrás precisando deste orbe quando os feitiços antigos esquecidos eram usados nessas profundezas. O orbe, no entanto, é guardado por um grande mal. Pergaminhos antigos falam de um portal que levará ao domínio do próprio Satã. Diz-se que a sala está escondida, mas tenho magia que me ajudará em sua localização. O portal não deixa ninguém passar, mas apenas aqueles que sabem o verdadeiro nome do demônio que espreita do outro lado. Se o sábio em " + RandomThings.GetRandomCity() + " falar a verdade, então 'Lúcifer' é o nome do demônio e eu precisarei gritá-lo quando encontrar o portão infernal. Primeiro devo ir para " + RandomThings.GetRandomCity() + ", onde espero encontrar aliados para a batalha que se aproxima."; }
			else if ( book.BookTitle == "The Underworld Gate" ){ book.BookText = "Há lendas de um lugar mais escuro que o véu que cobre o céu à noite. Um mundo que nunca vê o sol e onde os mais vis habitam. Os tipos de homem nunca desejariam testemunhar tais coisas, mas os corajosos e aventureiros buscam este reino pelos rumores de riquezas que estão dentro. O Underworld é, de fato, real. Há muitos anos, monstros jorraram da caverna que leva a este abismo e encheram as terras de terror e destruição. Lord British e Barão Almric uniram forças e lideraram uma campanha por todo o mundo, empurrando a maioria deles de volta para o Underworld. Uma vez feito, Almric usou um feitiço há muito perdido para selar a entrada, trancando-os below da terra de Sosaria para sempre. Agora uma grande pedra bloqueia o caminho, coberta de runas mágicas que apenas o Barão Almric pode abrir. Mas o Barão foi morto pelo Retalhador de Véus, em uma tentativa fútil de resgatar sua filha. Embora ele tenha conseguido chegar à terra antes de cair em sua perdição, não se determinou onde ele foi enterrado. Alguns acreditam que ele está enterrado perto de " + RandomThings.GetRandomCity() + ", mas há rumores de que ele foi levado de volta para a casa de sua esposa em Skara Brae. Se a morte do Retalhador não ressuscitou seu cadáver para vagar pela terra, deve-se apenas encontrar seu túmulo e recuperar sua cabeça. Apresentá-la no grande portão rúnico pode quebrar o feitiço e abrir o selo para o Underworld. Deve-se, no entanto, ter cuidado com o Underworld, pois textos antigos afirmam que a feitiçaria é dificultada ao viajar pelo abismo."; }
			else if ( book.BookTitle == "The Elemental Titans" ){ book.BookText = "Os primeiros dias da Fortaleza de Obsidiana foram um tempo sombrio. O sangue das guerras fluía livremente enquanto os Drow lutavam contra os Zealans na grande luta da limpeza religiosa. Batalhas eram planejadas e executadas. Vidas foram perdidas em nome de crenças arcaicas. Enquanto isso, os Drow labutavam diariamente para construir a Fortaleza de Obsidiana, conforme ordenado pelo ser benevolente chamado Guardião. O medo do Destruidor era forte.<br><br>Anos de suor resultaram finalmente na conclusão da Fortaleza. Lá, os magos Drow se reuniam para focar suas energias na adoração dos Elementais. Tremendas forças mágicas foram usadas para coletar um mineral negro estranho e moldá-lo em um grande obelisco escuro. De dentro da Fortaleza, os seguidores canalizavam seus pensamentos através do obelisco para os quatro elementos, dando-lhes ainda mais poder. Logo eles haviam acumulado energia suficiente para se tornarem os grandes Titãs da Terra, Água, Ar e Fogo.<br><br>A guerra continuou, mas agora os Drow tinham assistência considerável. Lithos moveu as terras para prender os Zealans, enquanto Hydros removeu suas águas de seu alcance. Os fogos de Pyros rugiram e cresceram, alimentados pelos ventos de Stratos. Era apenas uma questão de desgaste antes que os Zealans e suas crenças mesquinhas caíssem. Então vieram as palavras finais de aviso do Guardião: 'Leve seu povo e parta da Fortaleza. O Destruidor chegou.' Quando os Drow deixaram a Fortaleza, o Guardião tentou destruí-la. Os Drow suplicaram pela ajuda dos Titãs. Eles não ficaram desapontados. Os quatro Titãs apareceram para desafiar o Guardião. A terra foi quase destruída enquanto rocha, chuva, vento e fogo caíam de cima. A batalha foi longa e feroz. Finalmente, no entanto, os Titãs retornaram vitoriosos. A terra, embora marcada pela terrível luta, ainda era deles. O Guardião havia fugido do Underworld, para sempre.<br><br>A grande batalha quebrou cinco pedaços do obelisco. O primeiro fragmento, chamado Coração da Terra, estava ligado a Lithos, o Titã da Terra. Hydros, o Titã da Água, estava ligado à Lágrima dos Mares. O terceiro fragmento, o Sopro do Ar, estava ligado a Stratos, o Titã do Ar. Um quarto fragmento estava ligado a Pyros, o Titã do Fogo. Há uma considerável especulação sobre um quinto fragmento. Aparentemente, a ponta do grande obelisco foi vista arremessada no ar quase inteiramente intacta. No entanto, ninguém nunca viu o item pousar, então sua localização permanece um mistério. Se todos os fragmentos fossem reunidos e levados para a Fortaleza de Obsidiana, poderia ser possível criar um obelisco separado. Claro, também seria necessário fabricar um campo mágico de algum tipo para canalizar a energia de qualquer fonte que primeiro deu poder ao obelisco. Alguns acreditam que um grande guerreiro Zealan, Khumash-Gor, encontrou a Ponta do Obelisco. Isso é provavelmente apenas lenda, pois Khumash-Gor morreu séculos atrás, durante a grande guerra do Underworld.<br><br>Coletar os pedaços de rocha negra é algo que meros mortais nunca alcançarão. Sem a Ponta do Obelisco, um homem mortal não pode nem mesmo mover os outros pedaços de rocha negra. Se alguém encontrasse esta relíquia perdida, possuiria os meios para um dia se tornar um poderoso Titã do Éter.."; }
			else if ( book.BookTitle == "The Dragon's Egg" ){ book.BookText = "Os anões são um povo orgulhoso e fizemos de muitas montanhas em Lodor nosso lar. Entristece o coração ver meu povo sucumbir a esta praga que se espalhou de norte a sul. Estamos morrendo, e os mais velhos e sábios entre nós não conseguem determinar a causa. Parece uma doença, mas herbalistas são incapazes de curá-la. Aqueles com magia tentaram, mas morreram na tentativa. Estamos amaldiçoados e em breve deixaremos de existir.<br><br>Muitos de nossos lares estão sendo habitados por demônios ou mortos. Aqueles que faziam as armaduras e armas de nossos clãs não existem mais. Apenas alguns de nós restam e nos aglomeramos na esperança de evitar o destino dos outros. Eu era um mestre de dragões, que era uma habilidade especial antes que tipos como elfos se civilizassem. Antes que os elfos fossem capazes de domar tais bestas, nós, mestres de dragões, encontraríamos os ovos de grandes dragões ou serpes. Nós coletávamos o que era necessário para garantir que ele pudesse chocar. Com os mestres de dragões sendo os primeiros avistados pelas bestas, elas rapidamente seguiam nossa liderança e nos tratavam como se fôssemos suas mães. Elas lutariam conosco contra as legiões dos mortos e os vis elfos negros que vêm aos nossos domínios.<br><br>Lembro-me de aprender o domínio dos dragões em tenra idade. Meu pai matava um dragão poderoso e trazia o ovo para casa para minha mãe. Para ver se havia um dragão vivo dentro dele, tínhamos que levar o ovo para o poço de lava na Morada de Rhundar. Rhundar era o lar dos artesãos mais notáveis, e a luz do poço era tão brilhante que podíamos ver através da casca poderosa dos ovos. Agora Rhundar está em ruínas, pois os mortos destruíram tudo que vivia lá. Agora apenas a chamamos de Engano, para não nos lembrarmos da grandeza que um dia foi.<br><br>Uma vez que víamos um dragão vivo dentro, tínhamos que preparar as poções dos quatro elementos e aplicar os líquidos na casca. Então ela amolecia para que o bebê dragão pudesse quebrar a liberdade. A combinação das poções fazia com que o jovem se desenvolvesse rapidamente após o nascimento, o que os tornava companheiros favoráveis imediatamente. Tive muitos dragões de estimação, mas não pudemos mantê-los depois que a praga começou. Nós os libertamos, onde a maioria deles buscou abrigo em Destard. Sentirei saudades desses dias, e me entristece não ter filhos para ensinar isso."; }
			else if ( book.BookTitle == "Magic in the Moon" ){ book.BookText = "Começou como um orbe no céu, e demos a ele o nome de Luna. Esperávamos o sol se pôr para poder contemplá-lo. A lua chamada Luna vinha em certos momentos e rapidamente registramos as diferentes fases da lua. Isso nos ajudou a descobrir os muitos efeitos que a lua tem sobre Sosaria. Os necromantes aprenderam que quando a lua estava mais cheia, os licantropos seriam mais proeminentes e poderosos. Os feiticeiros aprenderam que os portões mágicos por toda a terra levariam a lugares diferentes com base nessas fases. Foi quando começamos a chamá-los de portões lunares. A lua detém tanto poder mágico, que os mais sábios entre nós se reuniam diariamente para criar um feitiço poderoso o suficiente para nos ajudar a alcançar o objeto celestial.<br><br>Após quase 20 anos de pesquisa, encontramos uma maneira de tomar o poder de um único portão lunar e mantê-lo dentro de um pequeno orbe místico que foi feito de vidro meteórico. Isso teve o efeito de drenar a magia dos portões lunares, a ponto de agora se poder controlar para onde são levados se entrarem em um e souberem para onde ir.<br><br>Pegamos essa magia capturada e colocamos o orbe no pedestal do Santuário da Feitiçaria. Então demos nossos primeiros passos para a lua. O planeta era pequeno, cinza e craterado, mas espaçoso para construir castelos e aldeias, então construímos nossa cidade de Dawn.<br><br>Com a ajuda da conjuração, Luna foi construída em apenas dez revoluções ao redor de Sosaria. Tínhamos um lugar para pesquisar nossa magia com segurança e não mais nos preocupávamos com a feitiçaria ser acidentalmente liberada em Sosaria.<br><br>Tentamos trazer visitantes para a lua, mas o puro poder da superfície lunar rejeita aqueles que não são poderosos o suficiente com tais energias. Então esta tem sido nossa casa para magos, bruxas, warlocks e feiticeiros. Os mestres de guild encontraram um asteroide nearby e construíram nosso salão principal de guild lá. Isso funcionou bem com o recrutamento de aprendizes, pois aqueles fracos com magia são capazes de viajar para o asteroide para começar seus estudos. Um dia, eles serão capazes de vir para a lua e talvez construir uma casa própria."; }
			else if ( book.BookTitle == "The Maze of Wonder" ){ book.BookText = "Antes que a escuridão preenchesse o Rei Durmas IV, ele era um governante sábio e bondoso. A maioria esquece os contos de suas façanhas contra o mal e a alegria que ele trouxe a seus súditos. Ele era um criador de arte e beleza, e isso ainda é visto hoje dentro de seu labirinto de sebe. O túmulo do Rei está dentro do labirinto, mas o mal não surgiu o suficiente para corromper o labirinto inteiramente. A glória do labirinto permanece, mas esteja avisado de que criaturas agora atravessam o labirinto. Os homens amaldiçoados foram transformados em minotauros que guardam o túmulo, enquanto alguns continuam a viver dentro dele como um meio de solidão do mundo. Se você for corajoso e poderoso o suficiente, é algo que deve ser visitado. O Rei o construiu como uma maneira agradável de chegar à taverna animada no centro, mas agora ele mantém uma beleza perigosa que a maioria das pessoas teme."; }
			else if ( book.BookTitle == "The Pass of the Gods" ){ book.BookText = "Onde os anões foram outrora os mestres artesãos do mundo, sua extinção foi seguida pela arte de nossas terras élficas. Nós, elfos, criamos itens únicos e incomuns e os decoramos com cores luxuosas. Nossa busca por artesanato fino levou alguns de nós em uma jornada a vales distantes. Eles buscaram os picos mais altos das terras, pois pensavam que estar perto dos deuses proporcionaria tutela na criação de itens dignos de divindades. Sua jornada os levou às terras orks do Império Selvagem, onde encontraram a própria montanha que apenas testemunharam em seus sonhos. Nossos irmãos e irmãs nunca retornaram ao mundo de Lodoria, mas muitos tentam encontrar o caminho de sua peregrinação. Talvez eles também possam aprender sobre o artesanato guiado celestialmente."; }
			else if ( book.BookTitle == "Valley of Corruption" ){ book.BookText = "Nossa ordem é guiada pelo próprio princípio da natureza, neutralidade e a ordem natural das coisas. Vemos um equilíbrio no mundo que deve ser protegido e mantido. Nos últimos anos, este princípio tornou-se lentamente corrompido por forças vis que ainda não entendemos. Alguns de nossos irmãos e irmãs deixaram nossa ordem, em busca do mal. O que corrompe suas mentes é o poder sobre os outros. Eles não se importam mais com o equilíbrio do mundo, mas com sua própria ganância.<br><br>Isso foi mais evidente na ilha de Kuldar. Aquele mago maldito Vordo convenceu os druidas locais a se juntarem às suas legiões de usuários de magia, e então os demônios e sátiros corruptos se juntaram às fileiras. Íamos lidar com essa ameaça crescente, mas quando navegamos para a ilha, ela havia desaparecido. Navegamos pelos mares por dias pensando que talvez tivéssemos as coordenadas erradas, mas é como se ela nunca tivesse existido. Voltamos para casa, sem mais rumores sobre Vordo ou seus druidas malignos. Alguns dizem que Vordo desencadeou um feitiço que os condenou a todos, afundando a ilha no fundo das profundezas de Netuno. Nunca saberemos o que realmente aconteceu, mas as terras estão seguras daquele mago sombrio. O equilíbrio foi restaurado."; }
			else if ( book.BookTitle == "The Demon Shard" ){ book.BookText = "Por séculos, os bruxos costumavam tentar demônios a visitar este reino e prendê-los dentro de pentagramas de imenso poder. Seu objetivo era simples, escravizar um demônio para fazer o que o bruxo mandasse. Para transportar esses demônios dos pentagramas, eles teriam que prendê-los dentro de fragmentos de cristal de avarnium. Magos antigos às vezes tinham esses fragmentos, mas eles estão há muito mortos ou se juntaram às fileiras dos mortos. Encontrei um desses cristais e espero aprender os segredos do fragmento. Aprendi que se eu puder libertar o demônio, eles me deveriam uma dívida de vida por sua liberdade e me acompanhariam sem restrições. Sei que tenho que encontrar alguns fragmentos de poder para fundi-los com este cristal e, assim, estilhaçá-lo.<br><br>Consultarei os sábios para aprender a localização desses outros fragmentos, mas preciso saber com que tipo de demônio estou lidando. Encontrei um pergaminho antigo que me dá uma pista. Se eu conseguir chegar às Ilhas do Pavor e comandar um navio, posso navegar para a ilha onde o Templo do Sangue está. Lá, devo ser capaz de remover as primeiras magias protetoras que cobrem este fragmento em segredo. Lá, devo encontrar o vórtice de sangue e ficar dentro dele. Então usar o fragmento deve anular aquele feitiço para que eu possa ver dentro dele."; }
			else if (book.BookTitle == "The House of Holy Mercy") 
			{ 
			    book.BookText =
				"Ao longo da estrada que serpenteia perto da cidade de Grey ergue-se uma antiga fortaleza de pedra desgastada, outrora um lugar de guerra e vigilância,"+ 
				"agora inteiramente dedicado à compaixão. Esta fortaleza foi concedida às Irmãs da Casa da Santa Misericórdia por decreto da Liga dos Lordes de Montor,"+
				" que julgaram apropriado que seus muros não mais abrigassem soldados, mas sim os enfermos e os cansados. Dentro de seus salões habitam freiras e curandeiras devotadas"+
				" ao cuidado dos idosos, dos feridos e daqueles acometidos por doenças, não pedindo moeda alguma, salvo o que viajantes generosos e comerciantes locais"+
				" livremente doam.<br><br>Muitos devem suas vidas às mãos gentis que ali laboram. Diz-se que qualquer alma que deseje aprender as artes da cura pode"+
				" apresentar-se aos portões da fortaleza, pois as Irmãs acolhem todos que queiram ajudá-las no cuidado de seus pacientes e, ao fazê-lo,"+
				" aprendem tanto a misericórdia quanto a medicina.";
			}
			else if ( book.BookTitle == "Druids of Sosaria" ) 
			{ 
			    book.BookText =
				"Muito antes da ascensão de reis e cidades, caminhavam por Sosaria aqueles que não ouviam coroas ou brasões,"+
				" mas sim o sopro vivo da própria terra. Estes eram os druidas, guardiões dos caminhos antigos, que extraíam sua sabedoria"+
				" do vento, da pedra e do espírito. Entre eles está a Ordem Uivante, um círculo de druidas sintonizados com o espírito do lobo,"+
				" cujo totem sagrado é mantido sob vigilância constante em seu bosque na costa oeste de Sosaria.<br><br>"+
				"A Ordem Uivante ensina que o lobo é tanto caçador quanto guardião, selvagem e leal, e através da devoção espiritual"+
				" e do ritual de comunhão, seus escolhidos podem compartilhar dessas virtudes. Muitos de seus parentes aprendem o ofício secreto, permitindo-lhes"+
				" assumir a forma das feras com as quais forjaram um vínculo. Através do domínio do druidismo e do espiritualismo, estes"+
				" druidas podem assumir formas tanto temíveis quanto poderosas, tornando-se avatares vivos da natureza. Diz-se que quando a"+
				" lua está alta e o vento carrega um uivo distante, os druidas da Ordem Uivante estão vigiando, invisíveis, sempre guardando"+
				" o equilíbrio entre o homem e a natureza.";
			}
			else if ( book.BookTitle == "Antiquities" ){ book.BookText = "Itens raros são um objetivo para a maioria dos colecionadores da terra, pois eu mesmo poderia pagar bastante ouro por algo único. Meus dias de explorar as masmorras temíveis já passaram, mas outras almas corajosas conseguem trazer de volta itens há muito esquecidos nos corredores sombrios das moradias abandonadas onde o mal comumente espreita. Pode-se encontrar alguma arma ou armadura incomum que não é mais utilizável, mas pode ser decorativa para uma casa ou castelo rico. Outros itens raros podem ser encontrados na forma de couro, peles, tecido, licores, reagentes, joias ou itens místicos de magos há muito mortos. Outros podem ser relógios decorativos, vasos, estátuas ou pinturas de pessoas e paisagens de muito tempo atrás. Esses itens são frequentemente mantidos por aventureiros como troféus de suas aventuras. Outros preferem negociá-los por ouro. Alguém que é bom em lore de itens geralmente pode determinar o valor de tais itens e quem nos assentamentos pode querer os itens. Aqueles que não são bons em lore de itens ou identificação geralmente podem adivinhar quem pode querer o item. Esses itens não podem ser simplesmente vendidos para esses colecionadores, mas instead alguém apenas daria o item e o cidadão lhes daria uma quantidade apropriada de ouro. Normalmente, aqueles com habilidade em mercantilismo conseguirão mais ouro do que o aventureiro médio, mas o valor ainda pode ser grande. Então, se alguém deseja carregar tais tesouros, pode certamente aumentar sua riqueza apenas com as moedas que podem acumular."; }
			else if ( book.BookTitle == "Castle Griffin Roost" ) 
			{ 
			    book.BookText =
				"Em um tempo de grande perigo, quando sussurros de corrupção e tirania se espalhavam pelos reinos, um poderoso exército"+
				" foi convocado para as fronteiras orientais de Montor. Esta hoste não veio por estrada ou mar, mas por chamado divino, atraída"+
				" através da poderosa feitiçaria da exaltada sacerdotisa Tamysa. Clamando aos céus, ela suplicou"+
				" aos deuses que ajudassem os mortais a resistir à crescente maré do mal que assolava a terra.<br><br>"+
				"Suas preces foram atendidas. Nas praias, no mês seguinte, apareceu uma hoste de navios alados, suas velas brilhando"+
				" com luz sagrada. À sua frente estava um ser angélico de imenso poder, conhecido apenas como o Marechal Celestial, escoltado"+
				" por cavaleiros vestidos com armaduras radiantes e montados em grifos temíveis. Esses guerreiros não perderam tempo em seu propósito."+
				" Com a ajuda de mãos locais e determinação inabalável, ergueram uma poderosa fortificação que viria a ser conhecida"+
				" como Castelo do Pouso do Grifo, servindo como base de operações e baluarte contra a escuridão iminente.<br><br>"+
				"Pouco se sabe sobre os paladinos que habitam seus muros, nem sobre os códigos estritos pelos quais vivem. No entanto, seus feitos"+
				" falam alto. Do Pouso, cavaleiros são enviados em missões por toda a terra, auxiliando os desamparados, protegendo os inocentes"+
				" e abatendo aqueles que traficam o mal. Os grifos que eles criam são poderosos e leais, carregando seus cavaleiros"+
				" pelos céus em vigilância incansável. Muitos vilões tentaram derrubar a fortaleza, lançando ataques tanto sutis"+
				" quanto terríveis, mas até hoje seus muros permanecem intransponíveis, erguendo-se como um símbolo da ira divina e da justiça inabalável.";
			}
			else if (book.BookTitle == "The Dreamstone") {book.BookText = "Sou um estranho nesta terra, assim como fui para o espaço sem nome que me trouxe aqui. Guerra, sempre guerra. Forjei lâminas para reis e mendigos, e todos eles tinham sede da mesma coisa - sangue. Antigamente, pensava que o canto da bigorna e o sopro da forja eram a voz da própria criação. Agora ouço apenas ver os ecos da vida terminando no cinzas mornas da forja.<br><br>" + 
			"O aço tem uma memória amarga. Cada lâmina que fiz tem uma sombra em minha alma, e não consigo esquecer os gritos daqueles que caíram sob seu brilho. Há um cansaço sobre mim que nenhum descanso pode diminuir.<br><br>" + 
			"Era uma vez um metal diferente de qualquer outro, uma lenda sussurrada através das línguas dos anões e dos dragões. A Pedra dos Sonhos. Ela brilhava não com mera luz, mas com memórias - cores que nenhum homem poderia nomear, reflexos de mundos que poderiam ter existido. Dizem que ela caiu dos céus na primeira era, quando os dragões dominavam o céu e moldavam montanhas com seu fogo.<br><br>" + 
			"Eu o vi uma vez, há muito tempo, no oco do tesouro de um dragão. Ele cantou para mim uma melodia de saudade e promessa. Dizem que o maior dos anciãos guardava a Pedra dos Sonhos, cobiçando sua beleza assim como cobiçavam seu domínio sobre uma terra devastada. Não é um metal que possa ser extraído ou comprado. Deve ser conquistado ou retirado dos sonhos dos deuses.<br><br>" + 
			"Dizem que aqueles que possuem a Pedra dos Sonhos forjam armas que desafiam o corpo mortal, lâminas que lembram seu portador e obedecem à sua vontade. No entanto, tais presentes têm um custo. O metal se liga à alma de quem o empunha. Sua essência e a lâmina se tornam uma só - e quando o portador vacila, a arma também falha.<br><br>" + 
			"Já vi muita morte para perseguir tal beleza novamente. Mas para aqueles que a procuram... cuidado. Escuros são os sonhos daqueles que aprisionam avidamente tal metal, e terríveis serão as medidas que eles tomarão para mantê-lo. Há outros que o procuram - eu conheci um elfo de um reino esquecido em uma busca por ele, e um rei de um povo nobre que em épocas passadas usou a Pedra dos Sonhos como seu direito e herança, e tenho certeza que há outros com intenções mais ou menos nobre. Se alguém os procurasse com a pedra dos sonhos, tenho certeza de que as recompensas seriam grandes, assim como os requisitos para ganhar sua confiança. Tudo o que quero é fazer uma lâmina final, usada por aquele que deseja ver o fim da violência que nos cerca. Tudo o que quero é fazer uma lâmina final, usada por quem deseja ver o fim da violência que nos rodeia. Uma guerreira habilidosa com o coração que minha rainha há muito perdida já teve e só encontrou quando não importava mais.";}
			else if ( book.BookTitle == "A Balada do Príncipe das Trevas") {book.BookText = book.BookText = @" 
			O que segue abaixo é a última música gravada pelo único sobrevivente da 9ª expedição ao submundo.<br><br> 

			...E assim eu vi o que é mais vil,<br> 
			Sobre um trono congelado de crânios gritando,<br> 
			Coroado em um halo de fogo sombrio,<br> 
			Revestido com o mais negro dos metais.<br> 
			Ele se deleitava com a carne de feras aladas,<br> 
			Bebendo profundamente sua alma desvanecida,<br> 
			Como se o ato em si fosse ritual,<br> 
			Um sacramento em ode ao seu próprio funeral sem fim.<br><br> 
			E quando finalmente seu olhar caiu sobre mim,<br> 
			Ele sorriu - um crescente irregular de loucura,<br> 
			Pois em seus olhos dançava uma tempestade sem piedade,<br> 
			Selvagem como as marés de loucura que o geraram.<br><br> 
			Então veio sua voz...<br> 
			Ó deuses acima e abaixo, aquela voz—<br> 
			Um canto fúnebre estrondoso, rachado e quebrado,<br> 
			Ainda assim, vivo com um poder terrível e irresistível.<br><br> 
			Uivava sobre impérios afogados em veneno,<br> 
			De estrelas devoradas pelo desespero,<br> 
			De uma vida passada vagando pelas trincheiras<br> 
			de guerras ímpias e odiosas.<br><br> 
			Cantava sobre batalhas travadas com lâminas e feitiços,<br> 
			De triunfo contra as corroídas do inferno;<br> 
			Da perda sofrida através da fúria e do fogo,<br> 
			E os fracassos são abraçados com desejo imprudente.<br><br> 
			Pois tal é o Príncipe das Trevas—<br> 
			Uma criatura de glória e decadência,<br> 
			Orgulho e tragédia entrelaçados como algemas e correntes,<br> 
			Um senhor dos excessos, um tolo, uma lenda de tudo que é vão.<br><br> 
			E quando ele se levantou de seu trono arruinado,<br> 
			Sua sombra se espalhou como asas pela caverna sem teto,<br> 
			E as pedras sob meus pés tremeram de medo,<br> 
			O peso de sua terrível fama permanecia próximo.<br><br> 
			Ele falou então, naquela canção que revolucionou o mundo:<br> 
			Uma promessa de carnificina ainda por vir,<br> 
			Uma convocação para aqueles ousados ou estúpidos o suficiente<br> 
			Para desafiar seu domínio sobre tudo o que brilhava.<br><br> 
			E eu fugi —<br> 
			Pois nenhum coração mortal pode resistir a esse hino,<br> 
			Nenhuma mente sã pode enfrentar esse sorriso ruinoso<br> 
			No entanto, ainda ouço isso nas horas tranquilas...<br> 
			Aquela voz, aquela voz terrível,<br> 
			Chamando dos lugares mais profundos do mundo,<br> 
			Convidando-nos a lembrar—<br> 
			E tema-o.<br><br> 
			Pois o Príncipe das Trevas não desaparece.<br>
			Ele espera.<br>
			Ele tem fome.<br>
			Ele canta.<br><br>
			";}
		}
	}
}
